// Lightweight gate. Strict JSON Schema validation runs in the orchestrator.
// This level just rejects obvious garbage so we don't wake the ThinkPad worker for nothing.

const body = $input.first().json.body || $input.first().json;

const REQUIRED = [
  'schema_version', 'job_id', 'khep_id', 'variant_index', 'approved_at',
  'karat_target', 'base_template', 'tier', 'parameters', 'constraints', 'export_profiles'
];
const KARATS = ['24K', '22K', '21K', '18K', '14K'];

const missing = REQUIRED.filter(k => !(k in body));
if (missing.length) {
  return [{ json: { valid: false, error: `missing fields: ${missing.join(', ')}` } }];
}
if (body.schema_version !== '1.0.0') {
  return [{ json: { valid: false, error: `unsupported schema_version: ${body.schema_version}` } }];
}
if (!KARATS.includes(body.karat_target)) {
  return [{ json: { valid: false, error: `invalid karat_target: ${body.karat_target}` } }];
}
if (body.constraints?.abort_on_non_watertight !== true) {
  return [{ json: { valid: false, error: 'constraints.abort_on_non_watertight must be true' } }];
}
if (!Array.isArray(body.export_profiles) || body.export_profiles.length === 0) {
  return [{ json: { valid: false, error: 'export_profiles must be a non-empty array' } }];
}

return [{ json: { valid: true, payload: body } }];
